// CUDA Kernel for bench_block logic
// Each thread processes one chunk of size static_chunk_size
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_chunk_kernel(Element* data, Element* partial_sums, size_t total_elements) {
  size_t chunk_id = blockIdx.x * blockDim.x + threadIdx.x;
  size_t it_base = chunk_id * static_chunk_size;

  if (it_base >= total_elements) return;

  Element sum = 0;
  Element f = data[it_base]; // f = data[0] relative to chunk start

  size_t limit = it_base + static_chunk_size;
  if (limit > total_elements) limit = total_elements;

  for (size_t i = it_base; i < limit; i++) {
    Element t = data[i];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }

  partial_sums[chunk_id] = sum;
}

// Final reduction kernel
template <typename Element>
__global__ void reduce_sum_kernel(Element* partial_sums, Element* final_sum, size_t count) {
  Element sum = 0;
  for (size_t i = 0; i < count; i++) {
    sum += partial_sums[i];
  }
  *final_sum = sum;
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_dev) {
  constexpr size_t static_chunk_size = 4096;
  size_t num_chunks = (len + static_chunk_size - 1) / static_chunk_size;

  // Allocate temp storage for partial sums
  Element* partial_sums_dev;
  cudaMalloc(&partial_sums_dev, num_chunks * sizeof(Element));

  // Launch kernel
  int threads_per_block = 256;
  int blocks = (num_chunks + threads_per_block - 1) / threads_per_block;

  bench_chunk_kernel<Element, compute_iterations, static_chunk_size>
      <<<blocks, threads_per_block>>>(src_dev, partial_sums_dev, len);

  cudaError_t err = cudaDeviceSynchronize();
  if (err != cudaSuccess) {
      std::cerr << "CUDA Error: " << cudaGetErrorString(err) << std::endl;
      exit(1);
  }

  // Reduce
  Element final_sum_host;
  Element* final_sum_dev;
  cudaMalloc(&final_sum_dev, sizeof(Element));

  reduce_sum_kernel<Element><<<1, 1>>>(partial_sums_dev, final_sum_dev, num_chunks);
  cudaDeviceSynchronize();

  cudaMemcpy(&final_sum_host, final_sum_dev, sizeof(Element), cudaMemcpyDeviceToHost);

  // Write back to src[0] = sum
  cudaMemcpy(src_dev, &final_sum_host, sizeof(Element), cudaMemcpyHostToDevice);

  cudaFree(partial_sums_dev);
  cudaFree(final_sum_dev);

  return len;
}

// Warmup function
auto runbench_warmup(void* c, size_t size) {
  const int item_1 = size / sizeof(double);

  double* ptr_dev;
  cudaMalloc(&ptr_dev, size);

  // Initialize device memory to 0 (matching host initialization)
  cudaMemset(ptr_dev, 0, size);

  auto x_2 = std::chrono::steady_clock::now();

  bench_cuda<double, 16>(item_1, 1., -1., ptr_dev);

  auto item_0 = std::chrono::steady_clock::now() - x_2;
  cudaFree(ptr_dev);

  return std::chrono::duration_cast<std::chrono::microseconds>(item_0).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = std::chrono::steady_clock::now();
  op();
  auto timer_duration = std::chrono::steady_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();  
  std::vector<decltype(duration)> measurements;

  // Full runs
  for (int i = 1; total_runs > i; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  // Half runs (simulated by running again, as GPU thread count is fixed)
  for (int i = 1; total_half_thread_runs > i; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t x_4, int item_3)
      : memory_space_{x_4}, compute_iterations_{item_3} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c_host, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  // Allocate device memory
  float *c_as_float_dev;
  double *c_as_double_dev;
  int *c_as_int_dev;

  cudaMalloc(&c_as_float_dev, cs.element_count<float>() * sizeof(float));
  cudaMalloc(&c_as_double_dev, cs.element_count<double>() * sizeof(double));
  cudaMalloc(&c_as_int_dev, cs.element_count<int>() * sizeof(int));

  size_t count_float = cs.element_count<float>();
  size_t count_double = cs.element_count<double>();
  size_t count_int = cs.element_count<int>();

  // Initialize to 0
  cudaMemset(c_as_float_dev, 0, count_float * sizeof(float));
  cudaMemset(c_as_double_dev, 0, count_double * sizeof(double));
  cudaMemset(c_as_int_dev, 0, count_int * sizeof(int));

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(count_float, 1.f, -1.f, c_as_float_dev);
    });
  });

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(count_double, 1., -1., c_as_double_dev);
    });
  });

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(count_int, 1, -1, c_as_int_dev);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;

  cudaFree(c_as_float_dev);
  cudaFree(c_as_double_dev);
  cudaFree(c_as_int_dev);
}


template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

